PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?judge ?judgeLabel WHERE {
  wd:Q21852971 wdt:P155 ?season .
  ?season wdt:P246 "2" .
  ?season wdt:P925 ?judge .
  OPTIONAL {
    ?judge rdfs:label ?judgeLabel .
    FILTER(LANG(?judgeLabel) = 'en')
  }
}
